    }
    char *a = exp_str(1);
    char *b = exp_str(2);
    int result;
    if (is_int_str(a) && is_int_str(b)) {
        result = str_to_int(a) == str_to_int(b);
    } else {
        result = str_eq(a, b);
    }
    last_result = val_new_int(result);
    return RET_OK;
}

int cmd_ne() {
